mapper.select:
SELECT st.id, st.clinic_id, c.clinic_name, st.biz_type, st.biz_id, st.patient_id, p.patient_name, st.mobile, st.template_id, tpl.template_code, tpl.template_name, st.task_status, st.scheduled_at, st.sent_at, st.retry_count, st.fail_reason, st.created_at FROM sms_task st LEFT JOIN clinic c ON c.id = st.clinic_id LEFT JOIN patient p ON p.id = st.patient_id LEFT JOIN sms_template tpl ON tpl.id = st.template_id WHERE st.org_id = #{orgId}
AND st.clinic_id IN
#{clinicId}
AND 1 = 0
AND st.patient_id IN ( SELECT patient_id FROM patient_doctor_rel WHERE doctor_id = #{staffId} AND status = 1 UNION SELECT patient_id FROM appointment WHERE doctor_id = #{staffId} AND is_deleted = 0 UNION SELECT patient_id FROM medical_record WHERE doctor_id = #{staffId} AND is_deleted = 0 UNION SELECT patient_id FROM treatment_plan WHERE doctor_id = #{staffId} AND is_deleted = 0 )
AND 1 = 0
AND st.clinic_id = #{query.clinicId}
AND st.biz_type = #{query.bizType}
AND st.patient_id = #{query.patientId}
AND st.task_status = #{query.taskStatus}
AND st.mobile LIKE CONCAT('%', #{query.mobile}, '%')
ORDER BY st.created_at DESC, st.id DESC
